import{_ as t,o as h,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const s=JSON.parse('{"title":"ABNERP - Hệ thống Hoạch định Nguồn lực Doanh nghiệp","description":"","frontmatter":{"title":"ABNERP - Hệ thống Hoạch định Nguồn lực Doanh nghiệp"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),g={name:"index.md"};function i(o,n,e,d,l,u){return h(),r("div",null,[...n[0]||(n[0]=[a('<h1 id="abnerp-he-thong-hoach-đinh-nguon-luc-doanh-nghiep" tabindex="-1">ABNERP - Hệ thống Hoạch định Nguồn lực Doanh nghiệp <a class="header-anchor" href="#abnerp-he-thong-hoach-đinh-nguon-luc-doanh-nghiep" aria-label="Permalink to &quot;ABNERP - Hệ thống Hoạch định Nguồn lực Doanh nghiệp&quot;">​</a></h1><p>Chào mừng bạn đến với ABNERP - giải pháp <strong>Hoạch định Nguồn lực Doanh nghiệp (ERP)</strong> mã nguồn mở toàn diện, giúp doanh nghiệp vừa và nhỏ quản lý toàn bộ hoạt động vận hành trên một nền tảng thống nhất.</p><h2 id="tinh-nang-chinh" tabindex="-1">Tính năng chính <a class="header-anchor" href="#tinh-nang-chinh" aria-label="Permalink to &quot;Tính năng chính&quot;">​</a></h2><p>ABNERP cung cấp hơn 12 mô-đun nghiệp vụ được tích hợp chặt chẽ:</p><table tabindex="0"><thead><tr><th>Mô-đun</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Kế toán</strong></td><td>Quản lý sổ sách kế toán, báo cáo tài chính, thuế</td></tr><tr><td><strong>Quản lý Kho</strong></td><td>Theo dõi tồn kho, nhập/xuất, kiểm kê</td></tr><tr><td><strong>CRM</strong></td><td>Quản lý quan hệ khách hàng, cơ hội, quy trình bán hàng</td></tr><tr><td><strong>Bán hàng</strong></td><td>Quản lý đơn hàng, báo giá, hóa đơn bán hàng</td></tr><tr><td><strong>Mua hàng</strong></td><td>Quản lý đơn mua hàng, yêu cầu mua hàng, nhà cung cấp</td></tr><tr><td><strong>Sản xuất</strong></td><td>Quản lý lệnh sản xuất, định mức nguyên vật liệu (BOM), lập kế hoạch sản xuất</td></tr><tr><td><strong>Quản trị Nhân sự (HRM)</strong></td><td>Quản lý nhân viên, chấm công, lương, nghỉ phép</td></tr><tr><td><strong>Hỗ trợ</strong></td><td>Quản lý ticket hỗ trợ khách hàng</td></tr><tr><td><strong>Quản lý Chất lượng</strong></td><td>Quy trình kiểm soát chất lượng</td></tr><tr><td><strong>Dự án</strong></td><td>Quản lý dự án, nhiệm vụ, thời gian</td></tr><tr><td><strong>Tài sản</strong></td><td>Quản lý tài sản cố định và bảo trì</td></tr><tr><td><strong>Trang web</strong></td><td>Quản lý nội dung website, cửa hàng trực tuyến</td></tr></tbody></table><h2 id="bat-đau-nhanh" tabindex="-1">Bắt đầu nhanh <a class="header-anchor" href="#bat-đau-nhanh" aria-label="Permalink to &quot;Bắt đầu nhanh&quot;">​</a></h2><ul><li><a href="/abnerp/introduction.html">Giới thiệu về ABNERP</a> — Tìm hiểu tổng quan hệ thống</li><li><a href="/abnerp/setting-up.html">Thiết lập ABNERP</a> — Hướng dẫn cài đặt và cấu hình ban đầu</li><li><a href="/abnerp/company-setup.html">Thiết lập Công ty</a> — Tạo và cấu hình công ty</li><li><a href="/abnerp/item.html">Mặt hàng</a> — Quản lý danh mục sản phẩm, dịch vụ</li><li><a href="/abnerp/customer.html">Khách hàng</a> — Quản lý thông tin khách hàng</li><li><a href="/abnerp/supplier.html">Nhà cung cấp</a> — Quản lý nhà cung cấp</li></ul><h2 id="tai-nguyen" tabindex="-1">Tài nguyên <a class="header-anchor" href="#tai-nguyen" aria-label="Permalink to &quot;Tài nguyên&quot;">​</a></h2><ul><li><strong>Trang web</strong>: <a href="https://erp.abnasia.org" target="_blank" rel="noreferrer">https://erp.abnasia.org</a></li><li><strong>Mã nguồn</strong>: GitHub</li><li><strong>Cộng đồng</strong>: Diễn đàn người dùng ABNERP</li><li><strong>Tài liệu</strong>: Hướng dẫn sử dụng chi tiết từng mô-đun</li></ul><hr><p><em>ABNERP là bản dịch và phát triển dựa trên ERPNext — Hệ thống ERP mã nguồn mở hàng đầu thế giới.</em></p>',11)])])}const p=t(g,[["render",i]]);export{s as __pageData,p as default};
